#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct { char *name; int grade; } Student;
Student *make_student(const char *name, int grade) {
    Student *s = malloc(sizeof(Student));
    if (!s) return NULL;
    s->name = malloc(strlen(name) + 1);
    if (!s->name) { free(s); return NULL; }
    strcpy(s->name, name);
    s->grade = grade;
    return s;
}
void free_student(Student *s) { if (s) { free(s->name); free(s); } }
void print_student(const Student *s) { printf("%s : %d\n", s->name, s->grade); }
int main(void) {
    Student *alice = make_student("Alice", 18);
    Student *bob   = make_student("Bob",   15);
    print_student(alice);
    print_student(bob);
    free_student(alice);
    free_student(bob);
    return 0;
}

