#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* == EXEMPLE ================================================
 * Struct avec champ dynamique int* (tableau de notes)
 * Double allocation : struct + champ pointeur separe.
 * =========================================================== */
typedef struct { char *label; int *scores; int count; } Team;

Team *example_make_team(const char *label, int count) {
    Team *t = malloc(sizeof(Team));
    if (!t) return NULL;
    t->label = malloc(strlen(label) + 1);
    if (!t->label) { free(t); return NULL; }
    strcpy(t->label, label);
    t->scores = malloc(count * sizeof(int));
    if (!t->scores) { free(t->label); free(t); return NULL; }
    t->count = count;
    return t;
}
void example_free_team(Team *t) {
    if (t) { free(t->scores); free(t->label); free(t); }
}
void example_demo(void) {
    Team *t = example_make_team("Alpha", 2);
    if (!t) return;
    t->scores[0] = 90; t->scores[1] = 85;
    printf("%s : %d, %d\n", t->label, t->scores[0], t->scores[1]);
    example_free_team(t);
}
